import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../api/axiosConfig';

const Profile = () => {
  const { user, updateUserProfile } = useAuth();
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [profileImage, setProfileImage] = useState('');

  const [loading, setLoading] = useState(true);
  const [updating, setUpdating] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    const fetchProfile = async () => {
      try {
        const response = await axiosInstance.get('/api/users/profile');
        const data = response.data;
        setName(data.name || '');
        setEmail(data.email || '');
        setProfileImage(data.profileImage || '');
      } catch (err) {
        console.error(err);
        setError('Failed to fetch profile details. Please try again.');
      } finally {
        setLoading(false);
      }
    };

    fetchProfile();
  }, []);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) { // 2MB Limit
        setError('Image size must be less than 2MB');
        return;
      }
      setError('');
      const reader = new FileReader();
      reader.onloadend = () => {
        setProfileImage(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemoveImage = () => {
    setProfileImage('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (password && password !== confirmPassword) {
      setError('Passwords do not match');
      return;
    }

    if (password && password.length < 6) {
      setError('Password must be at least 6 characters long');
      return;
    }

    setUpdating(true);
    try {
      const payload = {
        name: name.trim(),
        email: email.trim(),
        profileImage,
      };

      if (password) {
        payload.password = password;
      }

      const response = await axiosInstance.put('/api/users/profile', payload);

      // Update local storage and context
      updateUserProfile({
        name: response.data.name,
        email: response.data.email,
        profileImage: response.data.profileImage,
      });

      setSuccess('Profile updated successfully!');
      setPassword('');
      setConfirmPassword('');
    } catch (err) {
      console.error(err);
      if (err.response?.data?.message) {
        setError(err.response.data.message);
      } else {
        setError('Failed to update profile. Please try again.');
      }
    } finally {
      setUpdating(false);
    }
  };

  const getInitials = (nameStr) => {
    if (!nameStr) return '?';
    return nameStr.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
  };

  if (loading) {
    return (
      <div className="container py-5 text-center" style={{ minHeight: '80vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <div className="spinner-border text-primary" role="status">
          <span className="visually-hidden">Loading...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="container py-5" style={{ minHeight: '90vh' }}>
      <div className="row justify-content-center">
        <div className="col-lg-10">

          {/* Header */}
          <div className="mb-4">
            <h1 className="section-title" style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 800, fontSize: '2.5rem' }}>
              My Profile
            </h1>
            <p className="text-secondary">Manage your personal information, profile photo, and security credentials</p>
          </div>

          <div className="row g-4">

            {/* Left Side: Photo & Quick Status Card */}
            <div className="col-md-4">
              <div className="glass-card p-4 text-center anim-fade-in" style={{ height: '100%' }}>

                {/* Photo Preview Container */}
                <div style={{ position: 'relative', width: 140, height: 140, margin: '0 auto 1.5rem auto' }}>
                  <div style={{
                    width: '100%',
                    height: '100%',
                    borderRadius: '50%',
                    overflow: 'hidden',
                    border: '3px solid var(--glass-border-strong)',
                    background: 'var(--glass-bg)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize: '3rem',
                    fontWeight: 700,
                    color: 'var(--text-primary)',
                    boxShadow: '0 8px 32px rgba(0, 0, 0, 0.15)'
                  }}>
                    {profileImage ? (
                      <img src={profileImage} alt="Profile" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                    ) : (
                      getInitials(name)
                    )}
                  </div>
                </div>

                <h3 style={{ fontSize: '1.25rem', fontWeight: 700, marginBottom: '0.25rem' }}>{name}</h3>
                <p className="text-secondary" style={{ fontSize: '0.88rem', marginBottom: '1.5rem' }}>{email}</p>

                {/* Badge for Role */}
                <div className="mb-4">
                  <span className={`badge-${user?.role === 'ADMIN' ? 'purple' : 'blue'}`} style={{ fontSize: '0.78rem', padding: '0.4rem 1rem' }}>
                    {user?.role === 'ADMIN' ? '👑 Administrator' : '🎓 Student'}
                  </span>
                </div>

                {/* Upload & Remove Controls */}
                <div className="d-flex flex-column gap-2">
                  <label className="btn btn-glass w-100" style={{ fontSize: '0.85rem', cursor: 'pointer' }}>
                    Upload New Image
                    <input type="file" accept="image/*" onChange={handleImageChange} style={{ display: 'none' }} />
                  </label>
                  {profileImage && (
                    <button type="button" className="btn btn-danger-glass w-100" style={{ fontSize: '0.85rem' }} onClick={handleRemoveImage}>
                      Remove Photo
                    </button>
                  )}
                </div>

                <div className="text-secondary mt-3" style={{ fontSize: '0.7rem' }}>
                  Supported formats: JPG, PNG, GIF (Max: 2MB)
                </div>

              </div>
            </div>

            {/* Right Side: Account Settings Form */}
            <div className="col-md-8">
              <div className="glass-card-strong p-4 p-md-5 anim-fade-in" style={{ height: '100%' }}>

                <h4 style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, marginBottom: '1.5rem' }}>Account Details</h4>

                {/* Alerts */}
                {error && (
                  <div className="alert-glass-danger p-3 mb-4" role="alert" style={{ fontSize: '0.875rem' }}>
                    ✕ {error}
                  </div>
                )}
                {success && (
                  <div className="alert-glass-success p-3 mb-4" role="alert" style={{ fontSize: '0.875rem' }}>
                    ✓ {success}
                  </div>
                )}

                <form onSubmit={handleSubmit}>

                  {/* Name and Email Row */}
                  <div className="row g-3 mb-4">
                    <div className="col-md-6">
                      <label htmlFor="prof-name" style={{ fontSize: '0.78rem', fontWeight: 600, letterSpacing: '0.06em', textTransform: 'uppercase', color: 'var(--text-secondary)', display: 'block', marginBottom: '0.5rem' }}>
                        Full Name
                      </label>
                      <input
                        type="text"
                        id="prof-name"
                        className="form-control input-glass"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        required
                      />
                    </div>

                    <div className="col-md-6">
                      <label htmlFor="prof-email" style={{ fontSize: '0.78rem', fontWeight: 600, letterSpacing: '0.06em', textTransform: 'uppercase', color: 'var(--text-secondary)', display: 'block', marginBottom: '0.5rem' }}>
                        Email Address
                      </label>
                      <input
                        type="email"
                        id="prof-email"
                        className="form-control input-glass"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        required
                      />
                    </div>
                  </div>

                  <hr style={{ borderColor: 'var(--glass-border-strong)', margin: '2rem 0' }} />

                  <h4 style={{ fontFamily: "'Space Grotesk', sans-serif", fontWeight: 700, marginBottom: '1.5rem' }}>Security Settings</h4>

                  {/* Password updates */}
                  <div className="row g-3 mb-4">
                    <div className="col-md-6">
                      <label htmlFor="prof-pass" style={{ fontSize: '0.78rem', fontWeight: 600, letterSpacing: '0.06em', textTransform: 'uppercase', color: 'var(--text-secondary)', display: 'block', marginBottom: '0.5rem' }}>
                        New Password (Optional)
                      </label>
                      <input
                        type="password"
                        id="prof-pass"
                        className="form-control input-glass"
                        placeholder="Leave blank to keep current"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                      />
                    </div>

                    <div className="col-md-6">
                      <label htmlFor="prof-confirm" style={{ fontSize: '0.78rem', fontWeight: 600, letterSpacing: '0.06em', textTransform: 'uppercase', color: 'var(--text-secondary)', display: 'block', marginBottom: '0.5rem' }}>
                        Confirm Password
                      </label>
                      <input
                        type="password"
                        id="prof-confirm"
                        className="form-control input-glass"
                        placeholder="Confirm new password"
                        value={confirmPassword}
                        onChange={(e) => setConfirmPassword(e.target.value)}
                      />
                    </div>
                  </div>

                  {/* Submit Button */}
                  <div className="mt-5">
                    <button type="submit" className="btn btn-glow-blue px-5" disabled={updating}>
                      {updating ? (
                        <span className="d-flex align-items-center gap-2">
                          <span className="spinner-border spinner-border-sm" />
                          Saving Changes...
                        </span>
                      ) : 'Save Changes'}
                    </button>
                  </div>

                </form>

              </div>
            </div>

          </div>

        </div>
      </div>
    </div>
  );
};

export default Profile;
